import{_ as n,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"70A. Absences On Defence Leave","description":"","frontmatter":{"title":"70A. Absences On Defence Leave","eba":"Doctors in Training 2022-2026","topics":["leave","employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/70A-absences-on-defence-leave.md","filePath":"ebas/doctors-in-training/leave/70A-absences-on-defence-leave.md"}'),r={name:"ebas/doctors-in-training/leave/70A-absences-on-defence-leave.md"};function s(c,e,i,d,h,l){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_70a-absences-on-defence-leave" tabindex="-1">70A. Absences On Defence Leave <a class="header-anchor" href="#_70a-absences-on-defence-leave" aria-label="Permalink to &quot;70A. Absences On Defence Leave&quot;">​</a></h1><p><strong>70A.1</strong> A Full-Time or Part-Time Doctor absent on defence service will be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid in respect of a period during which the Doctor was absent on defence service; and</p><p><strong>(b)</strong> the amount the Doctor could reasonably expect to have received from the Employer as earnings for that period had the Doctor not been absent on defence service.</p><p><strong>70A.2</strong> A Doctor will notify the Employer as soon as possible of the date they require absence on defence service. The Doctor will give the Employer proof that the absence relates to defence service, the duration of such absence and the amount received for the relevant defence service period.</p><p><strong>70A.3</strong> In this clause &#39;absence on defence service&#39; has the meaning contained in section 24A of the Defence Reserve Service (Protection) Act 2001 (Cth).</p><p>Example: The Doctor is on Defence Service leave for the duration of a particular pay period. Were the Doctor not on Defence Service leave in that pay period they would have worked on the Sunday and Monday evening shift of each week of the pay period. The Doctor is entitled to payment as though at work for each of the Sunday and Monday evening shifts, less the amount of payment (not including reimbursements) from the Defence Service for the equivalent time of the Sunday and Monday evening shifts.</p><p>Plain language terms: ADF leave, reservist leave.</p>',8)])])}const v=n(r,[["render",s]]);export{p as __pageData,v as default};
